proof_course.quote:
def rendu_minimal(montant, pieces):
    infini = montant + 1
    dp = [0] + [infini] * montant
    choix = [None] * (montant + 1)

    for m in range(1, montant + 1):
        for p in pieces:
            if p <= m and dp[m - p] != infini:
                candidat = dp[m - p] + 1
                if candidat < dp[m]:
                    dp[m] = candidat
                    choix[m] = p

proof_correction.quote:
def minimum_pieces(montant, pieces):
    infini = montant + 1
    dp = [0] + [infini] * montant
    for m in range(1, montant + 1):
        for p in pieces:
            if p <= m and dp[m - p] != infini:
                dp[m] = min(dp[m], dp[m - p] + 1)
    if dp[montant] == infini:
        return None
    return dp[montant]
